queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:performer_id ?cg . ?child a :Performers ; p:id ?cg . ?l p:circle_id ?pg . ?parent a :Circles ; p:id ?pg . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Circles } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?circleperformers a :CirclePerformers .
  ?performers a :Performers .
  ?circleperformers p:hasPerformers ?performers .
  ?circles a :Circles .
  ?circleperformers p:hasCircles ?circles .
  ?circles p:name ?name .
  ?performers p:type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:performer_id ?cg . ?child a :Performers ; p:id ?cg . ?l p:circle_id ?pg . ?parent a :Circles ; p:id ?pg . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Circles } }
  FILTER(?nf = ?total)
} }
}
